def convert_temperature(value: float, input_scale: str, output_scale: str) -> float:
    if input_scale == output_scale:
        return round(value, 2)

    if input_scale == 'C' and output_scale == 'F':
        return round((value * 9/5) + 32, 2)
    elif input_scale == 'F' and output_scale == 'C':
        return round((value - 32) * 5/9, 2)
    else:
        raise ValueError("Invalid input or output scale")

if __name__ == "__main__":
    value, input_scale, output_scale = input().split()
    value = float(value)
    result = convert_temperature(value, input_scale, output_scale)
    print(f"{result:.2f}")
